-- Attendance Management schema migration for PostgreSQL.
CREATE TABLE IF NOT EXISTS attendance_sessions (id varchar(36) PRIMARY KEY, college_id varchar(64) NOT NULL, session_id varchar(36) NOT NULL REFERENCES academic_sessions(id) ON DELETE RESTRICT, section_id varchar(36) NOT NULL REFERENCES sections(id) ON DELETE CASCADE, time_slot_id varchar(36) REFERENCES time_slots(id) ON DELETE SET NULL, timetable_entry_id varchar(36) REFERENCES timetable_entries(id) ON DELETE SET NULL, attendance_date date NOT NULL, teacher_id varchar(64) NOT NULL, teacher_name varchar(160) NOT NULL, status varchar(20) NOT NULL DEFAULT 'draft', remarks text, finalized_by varchar(64), finalized_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT uq_attendance_session_section_date_slot UNIQUE (college_id, section_id, attendance_date, time_slot_id));
CREATE TABLE IF NOT EXISTS attendance_records (id varchar(36) PRIMARY KEY, college_id varchar(64) NOT NULL, attendance_session_id varchar(36) NOT NULL REFERENCES attendance_sessions(id) ON DELETE CASCADE, student_id varchar(36) NOT NULL REFERENCES students(id) ON DELETE CASCADE, section_id varchar(36) NOT NULL REFERENCES sections(id) ON DELETE CASCADE, attendance_date date NOT NULL, status varchar(20) NOT NULL, late_minutes integer NOT NULL DEFAULT 0, remarks text, marked_by varchar(64) NOT NULL, marked_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT uq_attendance_record_session_student UNIQUE (attendance_session_id, student_id), CONSTRAINT ck_attendance_late_minutes_non_negative CHECK (late_minutes >= 0));
CREATE INDEX IF NOT EXISTS ix_attendance_sessions_college_section_date ON attendance_sessions(college_id, section_id, attendance_date);
CREATE INDEX IF NOT EXISTS ix_attendance_sessions_college_teacher_date ON attendance_sessions(college_id, teacher_id, attendance_date);
CREATE INDEX IF NOT EXISTS ix_attendance_records_college_student_date ON attendance_records(college_id, student_id, attendance_date);
CREATE INDEX IF NOT EXISTS ix_attendance_records_college_status_date ON attendance_records(college_id, status, attendance_date);
